    // else if (util.environment.IS_SOURCE_READ) return handlerRankingWebview()
    else if (util.environment.IS_SOURCE_READ) return handlerRankingAjax()
    else return []
}

// 排行榜，书签，首页，编辑部推荐，顺序相同
function handlerRankingAjaxAll() {
